// Salesforce: Fetch recently modified contacts
// Uses the OAuth token from the integration record
const integration = $input.first().json;
const accessToken = integration.access_token;
const instanceUrl = integration.instance_url;
const lastSync = integration.last_synced_at || new Date(Date.now() - 15 * 60 * 1000).toISOString();

return [{
  json: {
    ...integration,
    fetch_url: `${instanceUrl}/services/data/v59.0/query?q=SELECT+Id,FirstName,LastName,Email,Phone,MobilePhone,MailingStreet,MailingCity,MailingState,MailingPostalCode,Title,Company+FROM+Contact+WHERE+LastModifiedDate+>+${lastSync}`,
    auth_header: `Bearer ${accessToken}`,
    crm_type: 'salesforce'
  }
}];

// HubSpot: Fetch recently modified contacts
const integration = $input.first().json;
const accessToken = integration.access_token;
const lastSync = integration.last_synced_at 
  ? new Date(integration.last_synced_at).getTime() 
  : Date.now() - 15 * 60 * 1000;

return [{
  json: {
    ...integration,
    fetch_url: `https://api.hubapi.com/crm/v3/objects/contacts/search`,
    auth_header: `Bearer ${accessToken}`,
    request_body: {
      filterGroups: [{
        filters: [{
          propertyName: 'lastmodifieddate',
          operator: 'GTE',
          value: lastSync.toString()
        }]
      }],
      properties: ['firstname', 'lastname', 'email', 'phone', 'mobilephone', 'address', 'city', 'state', 'zip', 'jobtitle', 'company'],
      limit: 100
    },
    crm_type: 'hubspot'
  }
}];

// Pipedrive: Fetch recently modified persons
const integration = $input.first().json;
const accessToken = integration.access_token;
const domain = integration.company_domain || 'api';
const lastSync = integration.last_synced_at || new Date(Date.now() - 15 * 60 * 1000).toISOString();

return [{
  json: {
    ...integration,
    fetch_url: `https://${domain}.pipedrive.com/api/v1/persons?sort=update_time DESC&limit=100&since_timestamp=${lastSync}`,
    auth_header: `Bearer ${accessToken}`,
    crm_type: 'pipedrive'
  }
}];

// Zoho: Fetch recently modified contacts
const integration = $input.first().json;
const accessToken = integration.access_token;
const lastSync = integration.last_synced_at || new Date(Date.now() - 15 * 60 * 1000).toISOString();

return [{
  json: {
    ...integration,
    fetch_url: `https://www.zohoapis.com/crm/v5/Contacts/search?criteria=(Modified_Time:greater_than:${lastSync})&per_page=100`,
    auth_header: `Zoho-oauthtoken ${accessToken}`,
    crm_type: 'zoho'
  }
}];

// Normalize CRM contacts to Callengo format
const item = $input.first().json;
const crmType = $('Route by CRM Type').first().json.crm_type;
const companyId = $('Route by CRM Type').first().json.company_id;
let contacts = [];

switch (crmType) {
  case 'salesforce':
    contacts = (item.records || []).map(r => ({
      external_id: r.Id,
      full_name: `${r.FirstName || ''} ${r.LastName || ''}`.trim(),
      email: r.Email,
      phone: r.Phone || r.MobilePhone,
      address: [r.MailingStreet, r.MailingCity, r.MailingState, r.MailingPostalCode].filter(Boolean).join(', '),
      job_title: r.Title,
      company_name: r.Company,
      source: 'salesforce'
    }));
    break;
  case 'hubspot':
    contacts = (item.results || []).map(r => ({
      external_id: r.id,
      full_name: `${r.properties?.firstname || ''} ${r.properties?.lastname || ''}`.trim(),
      email: r.properties?.email,
      phone: r.properties?.phone || r.properties?.mobilephone,
      address: [r.properties?.address, r.properties?.city, r.properties?.state, r.properties?.zip].filter(Boolean).join(', '),
      job_title: r.properties?.jobtitle,
      company_name: r.properties?.company,
      source: 'hubspot'
    }));
    break;
  case 'pipedrive':
    contacts = (item.data || []).map(r => ({
      external_id: r.id?.toString(),
      full_name: r.name,
      email: r.email?.[0]?.value,
      phone: r.phone?.[0]?.value,
      address: r.postal_address,
      job_title: r.job_title,
      company_name: r.org_name,
      source: 'pipedrive'
    }));
    break;
  case 'zoho':
    contacts = (item.data || []).map(r => ({
      external_id: r.id,
      full_name: `${r.First_Name || ''} ${r.Last_Name || ''}`.trim(),
      email: r.Email,
      phone: r.Phone || r.Mobile,
      address: [r.Mailing_Street, r.Mailing_City, r.Mailing_State, r.Mailing_Zip].filter(Boolean).join(', '),
      job_title: r.Title,
      company_name: r.Account_Name?.name,
      source: 'zoho'
    }));
    break;
}

return contacts.map(c => ({
  json: {
    ...c,
    company_id: companyId
  }
}));
